<x-layouts.app title="{{ $user->name }} · NEXUS"><div class="n3-content"><div class="n3-wrap"><div class="n3-heading"><div><span class="n3-eyebrow">Player profile</span><h1>{{ $user->name }}</h1></div>@if($user->profile_url)<a class="n3-action primary" href="{{ $user->profile_url }}" target="_blank">Open Steam profile ↗</a>@endif</div><div class="n3-profile"><aside class="n3-panel n3-profile-card"><div class="n3-profile-cover">@if($user->avatar_url)<img src="{{ $user->avatar_url }}" alt="">@else<span>{{ mb_substr($user->name,0,1) }}</span>@endif</div><div class="n3-profile-id"><strong>{{ $user->name }}</strong><small>{{ $user->last_login_at?->diffForHumans()?:'NEXUS member' }}</small>@if($user->profile_url)<a href="{{ $user->profile_url }}" target="_blank">STEAM COMMUNITY ↗</a>@endif</div><div class="n3-profile-rank"><span><small>LEVEL</small><b>{{ max(1,(int)floor($summary['score']/1000)+1) }}</b></span><span><small>SCORE</small><b>{{ number_format($summary['score']) }}</b></span></div></aside><main class="n3-panel n3-profile-data"><header class="n3-panel-head"><div><span class="n3-eyebrow">Player information</span><h2>{{ app()->getLocale()==='bg'?'Информация за играча':'Player information' }}</h2></div></header><section class="n3-data-section"><h3>{{ app()->getLocale()==='bg'?'Обща информация':'Overview' }}</h3><div class="n3-data-grid"><span class="n3-data"><small>COUNTRY</small><b>{{ strtoupper($user->locale) }}</b></span><span class="n3-data"><small>VISIBILITY</small><b>PUBLIC</b></span><span class="n3-data"><small>MEMBER SINCE</small><b>{{ $user->created_at->format('d.m.Y') }}</b></span></div></section><section class="n3-data-section"><h3>{{ app()->getLocale()==='bg'?'Статистика':'Statistics' }}</h3><div class="n3-data-grid">@foreach([['SCORE',$summary['score']],['KILLS',$summary['kills']],['DEATHS',$summary['deaths']],['K/D',$summary['deaths']?number_format($summary['kills']/$summary['deaths'],2):$summary['kills']],['HEADSHOTS',$summary['headshots']],['PLAYTIME',intdiv($summary['playtime'],60).'h']] as $item)<span class="n3-data"><small>{{ $item[0] }}</small><b>{{ is_numeric($item[1])?number_format($item[1]):$item[1] }}</b></span>@endforeach</div></section><section class="n3-data-section"><h3>Steam identity</h3><div class="n3-data"><small>STEAM64</small><b>{{ $user->steam_id?:'NOT CONNECTED' }}</b></div></section>@if($user->playerStats->isNotEmpty())<section class="n3-data-section"><h3>Server statistics</h3>@foreach($user->playerStats as $stat)<div class="n3-profile-server"><span><b>{{ $stat->server?->name?:'Global' }}</b><small>{{ $stat->last_seen_at?->diffForHumans()?:'No session' }}</small></span><strong>{{ number_format($stat->score) }} pts</strong></div>@endforeach</section>@endif</main></div></div></div></x-layouts.app>
